/* ─── Tooltip Data ────────────────────────────────────────── */
const TOOLTIPS: Record<string, string> = {
    "Next.js": "Server-first React framework for SEO and performance",
    "TypeScript": "Strict type-checking for resilient code",
    "React": "Component-based UI library for interactive interfaces",
    "Python": "Versatile backend language for AI and data processing",
    "Node.js": "High-performance JavaScript runtime for scalable APIs",
    "AWS": "Enterprise-grade cloud infrastructure for global scale",
    "Vercel": "Edge network for fast global deployments",
    "Tailwind CSS": "Utility-first styling for rapid UI development",
    "OpenAI": "State-of-the-art language models for intelligent workflows",
    "Postgres": "Robust relational database for complex data",
};

/* Individual card — muted by default, glows on hover */
function TechCard({ name, icon, category }: TechItem) {
    const [isHovered, setIsHovered] = useState(false);

    return (
        <div
            className="group/card relative mx-4 flex flex-shrink-0 cursor-default items-center gap-3 rounded-xl border border-white/[0.06] bg-neutral-900/40 px-5 py-3.5 backdrop-blur-sm transition-all duration-300 hover:border-lime-500/40 hover:bg-lime-500/5 hover:shadow-lime-500/10"
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
        >
            {/* Tooltip */}
            <AnimatePresence>
                {isHovered && TOOLTIPS[name] && (
                    <motion.div
                        initial={{ opacity: 0, y: 4 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: 4 }}
                        transition={{ duration: 0.2 }}
                        className="pointer-events-none absolute bottom-full left-1/2 z-50 mb-3 -translate-x-1/2 whitespace-nowrap rounded-lg border border-white/10 bg-neutral-900/90 px-3 py-1.5 text-xs text-zinc-300 shadow-xl backdrop-blur-sm"
                    >
                        {TOOLTIPS[name]}
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Icon */}
            <span aria-hidden="true" className="text-zinc-600 transition-colors duration-300 group-hover/card:text-lime-400">
                {icon}
            </span>
            {/* Text */}
            <div>
                <p className="whitespace-nowrap text-sm font-semibold text-zinc-500 transition-colors duration-300 group-hover/card:text-white">
                    {name}
                </p>
                <p className="whitespace-nowrap text-xs text-zinc-700 transition-colors duration-300 group-hover/card:text-zinc-500">
                    {category}
                </p>
            </div>
        </div>
    );
}

/* ─── The Marquee component ───────────────────────────────── */
export default function TechStackMarquee() {
    const ref = useRef<HTMLElement>(null);
    const isInView = useInView(ref, { once: true, margin: "-60px" });

    return (
        <section ref={ref} className="relative overflow-hidden py-20 lg:py-24">
            {/* Subtle top + bottom hairlines */}
            <div className="mx-auto max-w-[90rem] px-6 lg:px-16">
                <div className="mb-12 h-px bg-gradient-to-r from-transparent via-white/8 to-transparent" />
            </div>

            {/* Header */}
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
                transition={{ duration: 0.7, ease: EASE }}
                className="mb-10 text-center"
            >
                <span className="mb-3 inline-flex items-center gap-2 text-xs font-semibold uppercase tracking-widest text-zinc-700">
                    <span className="h-px w-5 bg-zinc-800" />
                    our stack
                    <span className="h-px w-5 bg-zinc-800" />
                </span>
                <p className="text-sm text-zinc-600">
                    The tools we actually use every day. No filler logos.
                </p>
            </motion.div>

            {/* Marquee container */}
            <motion.div
                initial={{ opacity: 0 }}
                animate={isInView ? { opacity: 1 } : { opacity: 0 }}
                transition={{ duration: 0.9, delay: 0.15, ease: EASE }}
                className="tb-marquee-container relative"
            >
                {/* Left fade mask */}
                <div
                    aria-hidden="true"
                    className="pointer-events-none absolute inset-y-0 left-0 z-10 w-32 bg-gradient-to-r from-black to-transparent"
                />
                {/* Right fade mask */}
                <div
                    aria-hidden="true"
                    className="pointer-events-none absolute inset-y-0 right-0 z-10 w-32 bg-gradient-to-l from-black to-transparent"
                />

                {/* Track — duplicate the array for seamless loop */}
                <div className="flex overflow-hidden py-2">
                    <div className="tb-marquee-track flex">
                        {[...STACK, ...STACK].map((item, i) => (
                            <TechCard
                                key={`${item.name}-${i}`}
                                name={item.name}
                                icon={item.icon}
                                category={item.category}
                            />
                        ))}
                    </div>
                </div>
            </motion.div>

            {/* Hairline bottom */}
            <div className="mx-auto mt-12 max-w-7xl px-6 lg:px-12">
                <div className="h-px bg-gradient-to-r from-transparent via-white/8 to-transparent" />
            </div>
        </section>
    );
}
